import{c as a,Q as i,j as l,m as o}from"./chunks/framework.BXc4yaFE.js";const g=JSON.parse('{"title":"Building Shared Coding Guidelines for AI (and People Too)","description":"","frontmatter":{"url":"https://stackoverflow.blog/2026/03/26/coding-guidelines-for-ai-agents-and-people-too/","title":"Building Shared Coding Guidelines for AI (and People Too)","author":"Ryan Donovan","date":"2026-03-26T00:00:00.000Z","status":"SUCCESS","date_fetched":"2026-05-18T00:00:00.000Z"},"headers":[],"relativePath":"research/ai-articles/33-stackoverflow-coding-guidelines-ai.md","filePath":"research/ai-articles/33-stackoverflow-coding-guidelines-ai.md","lastUpdated":1779894392000}'),t={name:"research/ai-articles/33-stackoverflow-coding-guidelines-ai.md"};function r(n,e,s,d,c,p){return i(),l("div",null,[...e[0]||(e[0]=[o('<h1 id="_33-stack-overflow-coding-guidelines-for-ai-agents-and-people-too" tabindex="-1">33. Stack Overflow: Coding Guidelines for AI Agents and People Too <a class="header-anchor" href="#_33-stack-overflow-coding-guidelines-for-ai-agents-and-people-too" aria-label="Permalink to &quot;33. Stack Overflow: Coding Guidelines for AI Agents and People Too&quot;">​</a></h1><h2 id="核心摘要-繁體中文" tabindex="-1">核心摘要（繁體中文） <a class="header-anchor" href="#核心摘要-繁體中文" aria-label="Permalink to &quot;核心摘要（繁體中文）&quot;">​</a></h2><p>隨著軟體工程師越來越仰賴編碼代理，企業需要為 AI 制定明確的編碼標準。這些指南與傳統編碼指南不同，必須更具體、更示例化、更直白，以便 AI 模型能夠準確理解並遵循。</p><h3 id="主要建議" tabindex="-1">主要建議 <a class="header-anchor" href="#主要建議" aria-label="Permalink to &quot;主要建議&quot;">​</a></h3><p><strong>1. 建立基本規則</strong></p><ul><li>明確指定技術堆棧、編程原則和最佳實踐</li><li>確保 AI 代理使用與現有生產代碼相同的語言和函式庫</li><li>規則應涵蓋決策的「為什麼」，而非只列舉規則</li></ul><p><strong>2. 編碼決策標準化</strong></p><ul><li>變數命名慣例（例：camelCase vs snake_case）</li><li>縮進標準和版面配置規則</li><li>異常處理和日誌記錄方式</li><li>註解和文件撰寫規則</li></ul><p><strong>3. 文件品質至關重要</strong></p><ul><li>編寫清晰一致、避免習語表達的指南</li><li>「好的文件對所有編碼實體都相同」——無論人類或 AI</li><li>明確展示決策理由，幫助 AI 理解背景</li></ul><p><strong>4. 實例示範的力量</strong></p><ul><li>提供正確和錯誤實現的多個具體範例</li><li>展示所有指南的「黃金標準」參考檔案</li><li>使用真實的 codebase 片段而非假想例子</li></ul><p><strong>5. 建立持續改進迴圈</strong></p><ul><li>將編碼失敗視為改進指南的機會</li><li>與團隊保持開放對話，蒐集 AI 生成代碼的反饋</li><li>定期審視和更新指南</li></ul><p><strong>6. 代理上線整合</strong></p><ul><li>將標準整合至 <code>agents.md</code> 或 <code>.claude/</code> 等代理配置檔案</li><li>納入版本控制系統，與代碼一同演進</li><li>結合 Linters 和靜態分析工具強制執行</li><li>使用模型上下文協議（MCP）自動化遵循檢查</li></ul><h3 id="核心洞察" tabindex="-1">核心洞察 <a class="header-anchor" href="#核心洞察" aria-label="Permalink to &quot;核心洞察&quot;">​</a></h3><p>文章強調，AI 代理不會自動推理編碼標準。與其希望 AI「猜測」團隊的期望，不如投資寫清晰、具體的指南。這些指南同時提升人類開發者和 AI 代理的程式碼品質。</p><hr><h2 id="關鍵引用-數據" tabindex="-1">關鍵引用/數據 <a class="header-anchor" href="#關鍵引用-數據" aria-label="Permalink to &quot;關鍵引用/數據&quot;">​</a></h2><p>無具體統計數據，但文章強調：</p><blockquote><p>「好的文件對所有編碼實體都相同」</p><p>— Ryan Donovan, Stack Overflow Blog</p></blockquote><p>這意味著為 AI 寫的編碼指南，實際上也會讓人類開發者受益。清晰的規則促進團隊一致性，無論執行者是人或 AI。</p><hr>',24)])])}const h=a(t,[["render",r]]);export{g as __pageData,h as default};
